+    /// Numeric edge cases: integer overflow, float precision, division by zero,
+    /// very large/small numbers, and mixed-type arithmetic.
+    #[test]
+    fn test_conformance_numeric_edge_cases() {
+        let fconn = Connection::open(":memory:").unwrap();
+        let rconn = rusqlite::Connection::open_in_memory().unwrap();
+
+        let queries = [
+            // Integer boundaries
+            "SELECT 9223372036854775807",
+            "SELECT -9223372036854775808",
+            // Integer overflow wraps to float in SQLite
+            "SELECT 9223372036854775807 + 1",
+            "SELECT -9223372036854775808 - 1",
+            // Division
+            "SELECT 10 / 3",
+            "SELECT 10.0 / 3.0",
+            "SELECT 1 / 0",
+            "SELECT 1.0 / 0.0",
+            "SELECT 0 / 0",
+            // Modulo
+            "SELECT 10 % 3",
+            "SELECT -10 % 3",
+            "SELECT 10 % -3",
+            // Float precision
+            "SELECT 0.1 + 0.2",
+            "SELECT CAST(0.1 + 0.2 AS TEXT)",
+            // Very small/large floats
+            "SELECT 1e308",
+            "SELECT 1e-308",
+            // Comparisons across types
+            "SELECT 42 = 42.0",
+            "SELECT 42 = '42'",
+            "SELECT 42.0 = '42.0'",
+            // abs edge cases
+            "SELECT abs(-9223372036854775808)",
+            // round edge cases
+            "SELECT round(2.5)",
+            "SELECT round(3.5)",
+            "SELECT round(-2.5)",
+            "SELECT round(0.5)",
+            "SELECT round(1.5)",
+        ];
+
+        let mismatches = oracle_compare(&fconn, &rconn, &queries);
+        if !mismatches.is_empty() {
+            for m in &mismatches {
+                eprintln!("{m}\n");
+            }
+            panic!(
+                "{} numeric edge case conformance mismatches found",
+                mismatches.len()
+            );
+        }
+    }
